// n8n Redis v1 GET retorna { [keyName]: value } onde keyName é a chave literal.
// Como a chave tem pontos (@s.whatsapp.net), o dotNotation cria objetos aninhados.
// Verificamos TODAS as propriedades não-sistema para encontrar qualquer valor truthy.
const json = $json || {};
const hasPending = Object.entries(json)
  .filter(([k]) => !['error', 'message', 'name', 'stack'].includes(k))
  .some(([, v]) => v !== null && v !== undefined && v !== '' && v !== false);
return [{ json: { consentPending: hasPending ? 'sim' : 'nao' } }];

