let text='';
const nodeNames=["Call 'Sondagem'","Call 'Pitch'","Call 'Negociacao'","Call 'Matricula'","Call 'Retorno_mensagem'1"];
for(const name of nodeNames){
  try{
    const val=$items(name)[0]?.json?.resposta||$items(name)[0]?.json?.output||$items(name)[0]?.json?.mensagem||'';
    if(val){text=String(val).trim();break;}
  }catch(e){}
}
if(!text)return[{json:{parte:'Desculpe, houve um problema. Pode repetir?'}}];
function split(t,max=150){const parts=[];let cur='';const paras=t.split(/\n{2,}/);for(const p of paras){const tr=p.trim();if(!tr)continue;if(cur&&(cur+'\n\n'+tr).length<=max){cur+='\n\n'+tr;continue;}if(cur)parts.push(cur);if(tr.length<=max){cur=tr;continue;}const sents=tr.split(/(?<=[.!?])\s+/);cur='';for(const s of sents){if((cur+' '+s).trim().length<=max){cur=(cur+' '+s).trim();}else{if(cur)parts.push(cur);cur=s;}}}if(cur)parts.push(cur);return parts.filter(p=>p.trim().length>0);}
return split(text).map(parte=>({json:{parte}}));
